.vt-demo {
  display: flex;
  gap: 16px;
  padding: 20px;
}
.vt-card {
  padding: 20px;
  border-radius: 12px;
  background-color: rgb(255, 255, 255);
  border: 1px solid rgb(222, 226, 230);
  flex: 1;
}
.vt-card--expanded {
  flex: 2;
  background-color: rgb(240, 247, 255);
}
.vt-card-title {
  margin: 0 0 8px;
}
::view-transition-old(*) {
  animation-duration: 0.3s;
}
::view-transition-new(*) {
  animation-duration: 0.3s;
}
::view-transition-group(card-1),
::view-transition-group(card-2) {
  animation-duration: 0.3s;
}
::view-transition-group(title-1),
::view-transition-group(title-2) {
  animation-duration: 0.3s;
}

